function riskyDivide(a: number, b: number): number {
  if (b === 0) throw new Error("Division by zero");
  return a / b;
}

const inputs = [[10, 2], [15, 3], [8, 0], [20, 4]];

for (const [a, b] of inputs) {
  try {
    const result = riskyDivide(a, b);
    console.log(`${a} / ${b} = ${result}`);
  } catch (error) {
    // Must narrow before using
    if (error instanceof Error) {
      console.log(`Error: ${error.message}`);
    } else {
      console.log(`Unknown error: ${String(error)}`);
    }
  }
}

class AppError extends Error {
  constructor(
    message: string,
    public readonly code: string
  ) {
    super(message);
    this.name = "AppError";
  }
}

class ValidationError extends AppError {
  constructor(
    public readonly field: string,
    message: string
  ) {
    super(message, "VALIDATION_ERROR");
    this.name = "ValidationError";
  }
}

class NotFoundError extends AppError {
  constructor(resource: string, id: number | string) {
    super(`${resource} ${id} not found`, "NOT_FOUND");
    this.name = "NotFoundError";
  }
}

function handle(error: unknown): void {
  if (error instanceof ValidationError) {
    console.log(`Validation failed on '${error.field}': ${error.message}`);
  } else if (error instanceof NotFoundError) {
    console.log(`Not found (${error.code}): ${error.message}`);
  } else if (error instanceof Error) {
    console.log(`General error: ${error.message}`);
  }
}

handle(new ValidationError("email", "Invalid email format"));
handle(new NotFoundError("User", 42));
handle(new Error("Something unexpected"));

interface ApiError {
  message:    string;
  code:       string;
  statusCode: number;
  timestamp:  string;
}

const createError = {
  badRequest: (message: string): ApiError => ({
    message, code: "BAD_REQUEST", statusCode: 400,
    timestamp: new Date().toISOString().slice(0, 10),
  }),
  unauthorized: (): ApiError => ({
    message: "Authentication required", code: "UNAUTHORIZED", statusCode: 401,
    timestamp: new Date().toISOString().slice(0, 10),
  }),
  notFound: (resource: string): ApiError => ({
    message: `${resource} not found`, code: "NOT_FOUND", statusCode: 404,
    timestamp: new Date().toISOString().slice(0, 10),
  }),
};

const errors: ApiError[] = [
  createError.badRequest("Missing required field: email"),
  createError.unauthorized(),
  createError.notFound("User"),
];

for (const err of errors) {
  console.log(`${err.statusCode} ${err.code}: ${err.message}`);
}

type Result<T, E = Error> =
  | { ok: true;  value: T }
  | { ok: false; error: E };

function ok<T>(value: T): Result<T> {
  return { ok: true, value };
}

function fail<T>(error: Error): Result<T> {
  return { ok: false, error };
}

function parseAge(input: string): Result<number> {
  const n = parseInt(input, 10);
  if (isNaN(n))          return fail(new Error(`"${input}" is not a number`));
  if (n < 0 || n > 150)  return fail(new Error(`Age ${n} is out of range`));
  return ok(n);
}

const inputs = ["25", "abc", "-5", "42", "200"];

for (const input of inputs) {
  const result = parseAge(input);
  if (result.ok) {
    console.log(`Valid age: ${result.value}`);
  } else {
    console.log(`Invalid: ${result.error.message}`);
  }
}

type Result<T> = { ok: true; value: T } | { ok: false; error: string };

function ok<T>(value: T): Result<T>      { return { ok: true, value }; }
function fail<T>(error: string): Result<T> { return { ok: false, error }; }

function mapResult<T, U>(r: Result<T>, fn: (v: T) => Result<U>): Result<U> {
  return r.ok ? fn(r.value) : r;
}

function parseNumber(s: string): Result<number> {
  const n = parseFloat(s);
  return isNaN(n) ? fail(`"${s}" is not a number`) : ok(n);
}

function ensurePositive(n: number): Result<number> {
  return n > 0 ? ok(n) : fail(`${n} must be positive`);
}

function ensureInteger(n: number): Result<number> {
  return Number.isInteger(n) ? ok(n) : fail(`${n} must be an integer`);
}

const inputs = ["42", "-5", "3.14", "100", "abc"];

for (const input of inputs) {
  const result = mapResult(
    mapResult(parseNumber(input), ensurePositive),
    ensureInteger
  );
  console.log(result.ok ? `✓ ${result.value}` : `✗ ${result.error}`);
}

type Result<T> = { ok: true; value: T } | { ok: false; error: Error };

async function tryCatch<T>(fn: () => T | Promise<T>): Promise<Result<T>> {
  try {
    const value = await fn();
    return { ok: true, value };
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    return { ok: false, error: err };
  }
}

async function fetchData(id: number): Promise<string> {
  if (id <= 0) throw new Error("ID must be positive");
  if (id > 100) throw new Error("ID not found");
  return `Data for ID ${id}`;
}

async function main() {
  const ids = [1, 50, -1, 200];
  for (const id of ids) {
    const result = await tryCatch(() => fetchData(id));
    if (result.ok) {
      console.log(`✓ ${result.value}`);
    } else {
      console.log(`✗ ${result.error.message}`);
    }
  }
}

main();

class Connection {
  private name: string;
  private open = false;

  constructor(name: string) { this.name = name; }

  connect(): void {
    this.open = true;
    console.log(`[${this.name}] Connected`);
  }

  query(sql: string): string {
    if (!this.open) throw new Error("Connection is closed");
    if (sql.includes("DROP")) throw new Error("DROP statements not allowed");
    return `Result of: ${sql}`;
  }

  close(): void {
    this.open = false;
    console.log(`[${this.name}] Disconnected`);
  }
}

function runQuery(conn: Connection, sql: string): void {
  conn.connect();
  try {
    const result = conn.query(sql);
    console.log(`  ✓ ${result}`);
  } catch (error) {
    if (error instanceof Error) console.log(`  ✗ ${error.message}`);
  } finally {
    conn.close();  // ALWAYS runs
  }
}

runQuery(new Connection("DB1"), "SELECT * FROM users");
runQuery(new Connection("DB2"), "DROP TABLE users");

class NetworkError extends Error {
  constructor(message: string, public readonly statusCode: number) {
    super(message);
    this.name = "NetworkError";
  }
}

class TimeoutError extends NetworkError {
  constructor() {
    super("Request timed out", 408);
    this.name = "TimeoutError";
  }
}

function simulateRequest(type: string): string {
  if (type === "timeout") throw new TimeoutError();
  if (type === "auth")    throw new NetworkError("Unauthorized", 401);
  if (type === "crash")  throw new Error("Unexpected crash");
  return "Success";
}

const requests = ["ok", "timeout", "auth", "crash"];

for (const type of requests) {
  try {
    const result = simulateRequest(type);
    console.log(`✓ ${result}`);
  } catch (error) {
    if (error instanceof TimeoutError) {
      console.log(`⏳ Retrying after timeout...`);
    } else if (error instanceof NetworkError) {
      console.log(`🔒 Auth error ${error.statusCode}: ${error.message}`);
    } else {
      // Re-throw unknown errors — we can't handle them here
      console.log(`💥 Unhandled: ${error instanceof Error ? error.message : String(error)}`);
    }
  }
}

function assertDefined<T>(value: T | null | undefined, name: string): asserts value is T {
  if (value === null || value === undefined) {
    throw new Error(`${name} must not be null or undefined`);
  }
}

function assertPositive(value: number, name: string): asserts value is number {
  if (value <= 0) {
    throw new Error(`${name} must be positive, got ${value}`);
  }
}

function processOrder(userId: number | null, amount: number | undefined) {
  assertDefined(userId, "userId");
  assertDefined(amount, "amount");
  assertPositive(amount, "amount");

  // After assertions: userId is number, amount is positive number
  console.log(`Processing order: user=${userId}, amount=$${amount}`);
}

try { processOrder(42, 99.99); } catch (e: unknown) { console.log(`Error: ${(e as Error).message}`); }
try { processOrder(null, 99.99); } catch (e: unknown) { console.log(`Error: ${(e as Error).message}`); }
try { processOrder(42, -10); } catch (e: unknown) { console.log(`Error: ${(e as Error).message}`); }

interface FormData {
  username: string;
  email: string;
  age: string;
  password: string;
}

function validateForm(data: FormData): string[] {
  const errors: string[] = [];

  if (data.username.length < 3)
    errors.push("Username must be at least 3 characters");

  if (!data.email.includes("@"))
    errors.push("Email must contain @");

  const age = parseInt(data.age, 10);
  if (isNaN(age) || age < 18)
    errors.push("Must be 18 or older");

  if (data.password.length < 8)
    errors.push("Password must be at least 8 characters");

  return errors;
}

const invalidForm: FormData = {
  username: "ab",
  email:    "notanemail",
  age:      "16",
  password: "short",
};

const validForm: FormData = {
  username: "alice_dev",
  email:    "alice@example.com",
  age:      "28",
  password: "securepassword123",
};

const errors1 = validateForm(invalidForm);
const errors2 = validateForm(validForm);

console.log(`Invalid form: ${errors1.length} errors`);
errors1.forEach(e => console.log(`  - ${e}`));
console.log(`Valid form: ${errors2.length} errors`);

interface SerializedError {
  name:    string;
  message: string;
  code?:   string;
  stack?:  string;
}

class ApiError extends Error {
  constructor(message: string, public readonly code: string) {
    super(message);
    this.name = "ApiError";
  }
}

function serializeError(error: unknown): SerializedError {
  if (error instanceof ApiError) {
    return { name: error.name, message: error.message, code: error.code };
  }
  if (error instanceof Error) {
    return { name: error.name, message: error.message };
  }
  return { name: "UnknownError", message: String(error) };
}

const errors: unknown[] = [
  new ApiError("Rate limit exceeded", "RATE_LIMIT"),
  new TypeError("Cannot read property of null"),
  "Something went wrong",
];

for (const error of errors) {
  const serialized = serializeError(error);
  console.log(JSON.stringify(serialized));
}

class DatabaseError extends Error {
  constructor(message: string, public readonly query?: string) {
    super(message); this.name = "DatabaseError";
  }
}

class HttpError extends Error {
  constructor(message: string, public readonly statusCode: number) {
    super(message); this.name = "HttpError";
  }
}

type AppLayerError = DatabaseError | HttpError;

function formatError(error: AppLayerError): string {
  if (error instanceof DatabaseError) {
    const queryInfo = error.query ? ` (query: ${error.query})` : "";
    return `DB Error${queryInfo}: ${error.message}`;
  } else {
    return `HTTP ${error.statusCode}: ${error.message}`;
  }
}

const errors: AppLayerError[] = [
  new DatabaseError("Connection refused"),
  new HttpError("Service unavailable", 503),
  new DatabaseError("Syntax error", "SELECT * FORM users"),
  new HttpError("Not found", 404),
];

for (const err of errors) {
  console.log(formatError(err));
}
